using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ── Shared state ───────────────────────────────────────────────────

var notebook = new Notebook();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd(
    "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

// ── Tools ──────────────────────────────────────────────────────────

var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWeb, "search_web"),
    AIFunctionFactory.Create(SaveNote,  "save_note"),
    AIFunctionFactory.Create(GetNotes,  "get_notes"),
};

// ── Chat client with automatic function invocation ─────────────────

IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// ── Determine the research topic ───────────────────────────────────

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// ── Run the agent ──────────────────────────────────────────────────

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to thoroughly research a given topic
        using the tools available to you.

        Workflow:
        1. Break the topic into 2-3 key questions you need to answer.
        2. Use the search_web tool to find information for each question.
        3. Use the save_note tool to record important findings with a category label.
        4. After gathering enough information, use get_notes to review everything.
        5. Produce a well-structured summary with sections and source citations.

        Be thorough but concise. Cite sources where possible.
        """),
    new(ChatRole.User,
        $"Research the following topic and provide a detailed summary:\n\n{topic}"),
};

var response = await client.GetResponseAsync(messages, new ChatOptions { Tools = tools });

Console.WriteLine("\n═══════════════════════════════════════════");
Console.WriteLine("  📋 RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine();

// ════════════════════════════════════════════════════════════════════
//  Tool Implementations
// ════════════════════════════════════════════════════════════════════

[Description("Search the web for information. Returns titles, snippets, and URLs.")]
async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");
    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";
        var html = await httpClient.GetStringAsync(url);
        var results = ParseSearchResults(html);

        if (results.Count == 0)
            return "No results found.";

        var sb = new StringBuilder();
        foreach (var (title, snippet, link) in results.Take(5))
        {
            sb.AppendLine($"Title: {title}");
            sb.AppendLine($"URL:   {link}");
            sb.AppendLine($"Snippet: {snippet}");
            sb.AppendLine();
        }
        return sb.ToString();
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

[Description("Save a research note with a category for later reference.")]
string SaveNote(
    [Description("Category label (e.g. 'Overview', 'Key Facts')")] string category,
    [Description("The content of the note")]                         string content,
    [Description("Source URL or reference, if any")]                  string? source = null)
{
    notebook.Add(category, content, source);
    Console.WriteLine($"  📝 Note saved under \"{category}\"");
    return $"Note saved under '{category}'. Total notes: {notebook.Count}";
}

[Description("Retrieve all saved research notes organized by category.")]
string GetNotes()
{
    Console.WriteLine("  📖 Reviewing notes...");
    return notebook.Count == 0
        ? "No notes saved yet."
        : notebook.ToString();
}

// ════════════════════════════════════════════════════════════════════
//  Helpers
// ════════════════════════════════════════════════════════════════════

static List<(string Title, string Snippet, string Url)> ParseSearchResults(string html)
{
    var results = new List<(string, string, string)>();

    var linkRx = new Regex(
        @"<a[^>]+class=""result__a""[^>]*href=""([^""]+)""[^>]*>(.*?)</a>",
        RegexOptions.Singleline);
    var snippetRx = new Regex(
        @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
        RegexOptions.Singleline);

    var links    = linkRx.Matches(html);
    var snippets = snippetRx.Matches(html);

    for (int i = 0; i < links.Count && i < snippets.Count; i++)
    {
        var rawUrl  = links[i].Groups[1].Value;
        var title   = StripHtml(links[i].Groups[2].Value);
        var snippet = StripHtml(snippets[i].Groups[1].Value);

        // DuckDuckGo wraps URLs in a redirect — extract the real target.
        var m = Regex.Match(rawUrl, @"uddg=([^&]+)");
        var url = m.Success ? Uri.UnescapeDataString(m.Groups[1].Value) : rawUrl;

        if (!string.IsNullOrWhiteSpace(title))
            results.Add((title.Trim(), snippet.Trim(), url));
    }
    return results;
}

static string StripHtml(string html) =>
    System.Net.WebUtility.HtmlDecode(Regex.Replace(html, @"<[^>]+>", ""));

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var topic = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(topic)
        ? "Recent advances in renewable energy technology"
        : topic;
}

// ════════════════════════════════════════════════════════════════════
//  Notebook – in-memory note storage
// ════════════════════════════════════════════════════════════════════

sealed class Notebook
{
    private readonly Dictionary<string, List<(string Content, string? Source)>> _entries = new();

    public int Count => _entries.Values.Sum(l => l.Count);

    public void Add(string category, string content, string? source)
    {
        if (!_entries.TryGetValue(category, out var list))
        {
            list = [];
            _entries[category] = list;
        }
        list.Add((content, source));
    }

    public override string ToString()
    {
        var sb = new StringBuilder();
        foreach (var (category, notes) in _entries)
        {
            sb.AppendLine($"## {category}");
            foreach (var (content, source) in notes)
            {
                sb.AppendLine($"- {content}");
                if (!string.IsNullOrEmpty(source))
                    sb.AppendLine($"  Source: {source}");
            }
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

